    _flushTimer = Timer.periodic(
      const Duration(seconds: 30),
      (_) => flush(),
    );
  }

  @override
  Future<void> write(LogEntry entry) async {
    _buffer.add(entry);
    if (_buffer.length >= _flushThreshold) {
      await flush();
    }
  }

