// --- Main Logger ---

class AppLogger {
  static AppLogger? _instance;
  late LogConfig _config;
  String? _currentUserId;

  AppLogger._();

  static AppLogger get instance {
    _instance ??= AppLogger._();
    return _instance!;
  }

  void initialize(LogConfig config) {
    _config = config;
    _log(LogLevel.info, 'system', 'Logger initialized', metadata: {
      'environment': config.environment.name,
      'minimumLevel': config.minimumLevel.name,
      'redactionEnabled': config.redactSensitiveData,
    });
  }

  void setUserId(String? userId) {
    if (userId != null && _config.redactSensitiveData) {
      // Hash the user ID for production logs
      _currentUserId = 'user_${userId.hashCode.toRadixString(16)}';
    } else {
      _currentUserId = userId;
    }
  }

  // --- Core Logging ---

  void verbose(String category, String message,
          {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.verbose, category, message, metadata: metadata);

  void debug(String category, String message,
          {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.debug, category, message, metadata: metadata);

  void info(String category, String message,
          {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.info, category, message, metadata: metadata);

  void warning(String category, String message,
          {Map<String, dynamic>? metadata, Object? error}) =>
      _log(LogLevel.warning, category, message,
          metadata: metadata, error: error);

  void error(String category, String message,
          {Map<String, dynamic>? metadata,
          Object? error,
          StackTrace? stackTrace}) =>
      _log(LogLevel.error, category, message,
          metadata: metadata, error: error, stackTrace: stackTrace);

  void fatal(String category, String message,
          {Map<String, dynamic>? metadata,
          Object? error,
          StackTrace? stackTrace}) =>
      _log(LogLevel.fatal, category, message,
          metadata: metadata, error: error, stackTrace: stackTrace);

  void _log(
    LogLevel level,
    String category,
    String message, {
    Map<String, dynamic>? metadata,
    Object? error,
    StackTrace? stackTrace,
    String? correlationId,
  }) {
    if (level.priority < _config.minimumLevel.priority) return;

    Map<String, dynamic>? safeMetadata = metadata;
    if (metadata != null && _config.redactSensitiveData) {
      safeMetadata = SensitiveDataRedactor.redactMap(metadata);
    }

    String safeMessage = message;
    if (_config.redactSensitiveData) {
      safeMessage = SensitiveDataRedactor.redactString(message);
    }

    final entry = LogEntry(
      timestamp: DateTime.now().toUtc(),
      level: level,
      category: category,
      message: safeMessage,
      metadata: safeMetadata,
      error: error?.toString(),
      stackTrace: (stackTrace != null && _config.includeStackTrace)
          ? stackTrace.toString()
          : null,
      correlationId: correlationId,
      userId: _currentUserId,
    );

    for (final output in _config.outputs) {
      output.write(entry);
    }
  }

  Future<void> flush() async {
    for (final output in _config.outputs) {
      await output.flush();
    }
  }

  Future<void> dispose() async {
    for (final output in _config.outputs) {
      await output.dispose();
    }
  }
}

// --- HTTP Logging Interceptor ---
// Designed to work with dio or http package

class HttpLogInterceptor {
  final AppLogger _logger = AppLogger.instance;
  static const String _category = 'http';

  /// Log an outgoing HTTP request
  void logRequest({
    required String method,
    required String url,
    Map<String, String>? headers,
    dynamic body,
    String? correlationId,
  }) {
    final metadata = <String, dynamic>{
      'method': method,
      'url': _sanitizeUrl(url),
      if (correlationId != null) 'correlationId': correlationId,
    };

    // Log headers (redaction happens in _log)
    if (headers != null) {
      metadata['headers'] = Map<String, dynamic>.from(headers);
    }

    // Log body with size limit
    if (body != null) {
      metadata['body'] = _truncateBody(body);
      if (body is String) {
        metadata['bodySize'] = body.length;
      }
    }

    _logger.info(_category, 'HTTP Request: $method ${_sanitizeUrl(url)}',
        metadata: metadata);
  }

  /// Log an incoming HTTP response
  void logResponse({
    required String method,
    required String url,
    required int statusCode,
    Map<String, String>? headers,
    dynamic body,
    Duration? duration,
    String? correlationId,
  }) {
    final metadata = <String, dynamic>{
      'method': method,
      'url': _sanitizeUrl(url),
      'statusCode': statusCode,
      if (duration != null) 'durationMs': duration.inMilliseconds,
      if (correlationId != null) 'correlationId': correlationId,
    };

    if (headers != null) {
      metadata['responseHeaders'] = Map<String, dynamic>.from(headers);
    }

    if (body != null) {
      metadata['responseBody'] = _truncateBody(body);
    }

    final level = statusCode >= 500
        ? LogLevel.error
        : statusCode >= 400
            ? LogLevel.warning
            : LogLevel.info;

    _logger._log(
      level,
      _category,
      'HTTP Response: $statusCode $method ${_sanitizeUrl(url)}'
          '${duration != null ? ' (${duration.inMilliseconds}ms)' : ''}',
      metadata: metadata,
    );
  }

  /// Log HTTP errors
  void logError({
    required String method,
    required String url,
    required Object error,
    StackTrace? stackTrace,
    Duration? duration,
    String? correlationId,
  }) {
    _logger.error(
      _category,
      'HTTP Error: $method ${_sanitizeUrl(url)}'
          '${duration != null ? ' (${duration.inMilliseconds}ms)' : ''}',
      metadata: {
        'method': method,
        'url': _sanitizeUrl(url),
        if (duration != null) 'durationMs': duration.inMilliseconds,
        if (correlationId != null) 'correlationId': correlationId,
      },
      error: error,
      stackTrace: stackTrace,
    );
  }

  String _sanitizeUrl(String url) {
    // Remove query parameters that might contain tokens
    try {
      final uri = Uri.parse(url);
      if (uri.queryParameters.isEmpty) return url;

      final safeParams = uri.queryParameters.map((key, value) {
        if (SensitiveDataRedactor.redactMap({key: value})[key] ==
            value) {
          return MapEntry(key, value);
        }
        return MapEntry(key, '[REDACTED]');
      });

      return uri.replace(queryParameters: safeParams).toString();
    } catch (_) {
      return url;
    }
  }

  dynamic _truncateBody(dynamic body) {
    if (body == null) return null;
    final str = body is String ? body : jsonEncode(body);
    const maxLen = 1024; // Configurable via LogConfig
    if (str.length > maxLen) {
      return '${str.substring(0, maxLen)}... [truncated, total: ${str.length} chars]';
    }
    return body;
  }
}

// --- Database Operation Logger ---

class DatabaseLogger {
  final AppLogger _logger = AppLogger.instance;
  static const String _category = 'database';

  void logQuery({
    required String operation,
    required String table,
    Map<String, dynamic>? parameters,
    int? resultCount,
    Duration? duration,
  }) {
    _logger.debug(_category, 'DB $operation on $table', metadata: {
      'operation': operation,
      'table': table,
      if (parameters != null) 'parameters': parameters,
      if (resultCount != null) 'resultCount': resultCount,
      if (duration != null) 'durationMs': duration.inMilliseconds,
    });
  }

  void logMigration({
    required int fromVersion,
    required int toVersion,
    required bool success,
    Duration? duration,
    Object? error,
  }) {
    final level = success ? LogLevel.info : LogLevel.error;
    _logger._log(
      level,
      _category,
      'DB Migration v$fromVersion -> v$toVersion: ${success ? 'SUCCESS' : 'FAILED'}',
      metadata: {
        'fromVersion': fromVersion,
        'toVersion': toVersion,
        'success': success,
        if (duration != null) 'durationMs': duration.inMilliseconds,
      },
      error: error,
    );
  }

  void logError({
    required String operation,
    required String table,
    required Object error,
    StackTrace? stackTrace,
  }) {
    _logger.error(
      _category,
      'DB Error during $operation on $table',
      metadata: {
        'operation': operation,
        'table': table,
      },
      error: error,
      stackTrace: stackTrace,
    );
  }
}

// --- Authentication Flow Logger ---
// NOTE: This NEVER logs actual credentials, tokens, or secrets

class AuthLogger {
  final AppLogger _logger = AppLogger.instance;
  static const String _category = 'auth';

  void logLoginAttempt({
    required String method, // 'email', 'google', 'apple', 'biometric', etc.
    // NOTE: We intentionally do NOT accept email/username/password parameters
  }) {
    _logger.info(_category, 'Login attempt', metadata: {
      'method': method,
      'timestamp': DateTime.now().toUtc().toIso8601String(),
    });
  }

  void logLoginSuccess({
    required String method,
    required String userId,
    // NOTE: We do NOT log the actual token
    bool? isNewUser,
  }) {
    // Set the user context for subsequent logs
    AppLogger.instance.setUserId(userId);

    _logger.info(_category, 'Login successful', metadata: {
      'method': method,
      if (isNewUser != null) 'isNewUser': isNewUser,
    });
  }

  void logLoginFailure({
    required String method,
    required String reason, // 'invalid_credentials', 'account_locked', 'network_error', etc.
    // NOTE: We log the failure REASON, not the credentials that failed
    Object? error,
  }) {
    _logger.warning(_category, 'Login failed', metadata: {
      'method': method,
      'reason': reason,
    }, error: error);
  }

  void logTokenRefresh({
    required bool success,
    String? reason,
  }) {
    // Log that a refresh occurred, NOT the token values
    if (success) {
      _logger.debug(_category, 'Token refresh successful');
    } else {
      _logger.warning(_category, 'Token refresh failed', metadata: {
        if (reason != null) 'reason': reason,
      });
    }
  }

  void logLogout({
    required String reason, // 'user_initiated', 'token_expired', 'forced', etc.
  }) {
    _logger.info(_category, 'User logged out', metadata: {
      'reason': reason,
    });
    AppLogger.instance.setUserId(null);
  }

  void logPasswordReset({required bool requested, bool? completed}) {
    // Log the event, never the password or reset token
    _logger.info(_category, 'Password reset', metadata: {
      'requested': requested,
      if (completed != null) 'completed': completed,
    });
  }

  void logMfaChallenge({
    required String type, // 'sms', 'totp', 'email'
    required bool success,
  }) {
    // Log the MFA event, never the OTP code
    _logger.info(_category, 'MFA challenge', metadata: {
      'type': type,
      'success': success,
    });
  }

  void logSessionEvent({
    required String event, // 'created', 'extended', 'expired', 'invalidated'
    Duration? sessionDuration,
  }) {
    _logger.info(_category, 'Session $event', metadata: {
      'event': event,
      if (sessionDuration != null)
        'sessionDurationMinutes': sessionDuration.inMinutes,
    });
  }
}

