  }

  void logPerformance({
    required String operation,
    required Duration duration,
    Map<String, dynamic>? metadata,
  }) {
    final level =
        duration.inMilliseconds > 3000 ? LogLevel.warning : LogLevel.debug;
    _logger._log(
      level,
      _category,
      'Performance: $operation took ${duration.inMilliseconds}ms',
      metadata: {
        'operation': operation,
        'durationMs': duration.inMilliseconds,
        if (metadata != null) ...metadata,
      },
    );
  }
}

// --- App Health Monitor ---

class AppHealthLogger {
  final AppLogger _logger = AppLogger.instance;
  static const String _category = 'health';

  void logAppStart({
    required Duration startupDuration,
    required String appVersion,
    required String buildNumber,
  }) {
    _logger.info(_category, 'App started', metadata: {
      'startupDurationMs': startupDuration.inMilliseconds,
      'appVersion': appVersion,
      'buildNumber': buildNumber,
      'platform': Platform.operatingSystem,
      'platformVersion': Platform.operatingSystemVersion,
    });
  }

  void logAppLifecycle(String state) {
    _logger.info(_category, 'App lifecycle: $state', metadata: {
      'state': state,
    });
  }

  void logMemoryWarning() {
    _logger.warning(_category, 'Memory warning received');
  }

  void logCrash({
    required Object error,
    required StackTrace stackTrace,
    String? context,
  }) {
    _logger.fatal(
      _category,
      'App crash${context != null ? ' in $context' : ''}',
      error: error,
      stackTrace: stackTrace,
    );
    // Ensure crash logs are flushed
    _logger.flush();
  }

  void logConnectivity({
    required bool isConnected,
    String? connectionType,
  }) {
    _logger.info(_category, 'Connectivity changed', metadata: {
      'connected': isConnected,
      if (connectionType != null) 'type': connectionType,
    });
  }
}

// --- Convenience Facade ---

class Log {
  static final AppLogger _logger = AppLogger.instance;
  static final HttpLogInterceptor http = HttpLogInterceptor();
  static final DatabaseLogger database = DatabaseLogger();
  static final AuthLogger auth = AuthLogger();
  static final InteractionLogger interaction = InteractionLogger();
  static final AppHealthLogger health = AppHealthLogger();

  /// Initialize the logging system
  static void init({AppEnvironment? environment}) {
    final env = environment ??
        (kReleaseMode
            ? AppEnvironment.production
            : kProfileMode
                ? AppEnvironment.staging
                : AppEnvironment.development);

    final config = switch (env) {
      AppEnvironment.development => LogConfig.development(),
      AppEnvironment.staging => LogConfig.staging(),
      AppEnvironment.production => LogConfig.production(),
    };

    _logger.initialize(config);
  }

  // Quick access to core logger
  static void v(String category, String message,
          {Map<String, dynamic>? metadata}) =>
      _logger.verbose(category, message, metadata: metadata);

  static void d(String category, String message,
          {Map<String, dynamic>? metadata}) =>
      _logger.debug(category, message, metadata: metadata);

  static void i(String category, String message,
          {Map<String, dynamic>? metadata}) =>
      _logger.info(category, message, metadata: metadata);

  static void w(String category, String message,
          {Map<String, dynamic>? metadata, Object? error}) =>
      _logger.warning(category, message, metadata: metadata, error: error);

  static void e(String category, String message,
          {Map<String, dynamic>? metadata,
          Object? error,
          StackTrace? stackTrace}) =>
      _logger.error(category, message,
          metadata: metadata, error: error, stackTrace: stackTrace);

  static void f(String category, String message,
          {Map<String, dynamic>? metadata,
          Object? error,
          StackTrace? stackTrace}) =>
      _logger.fatal(category, message,
          metadata: metadata, error: error, stackTrace: stackTrace);

  static Future<void> flush() => _logger.flush();
  static Future<void> dispose() => _logger.dispose();
}

// --- Usage Example ---

void exampleUsage() async {
  // Initialize once at app startup
  Log.init();

  // --- HTTP logging ---
  final stopwatch = Stopwatch()..start();
  Log.http.logRequest(
    method: 'POST',
    url: 'https://api.example.com/v1/users',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIs...',  // Will be redacted
    },
    body: {
      'email': 'user@example.com',  // Will be redacted
      'password': 'secret123',       // Will be redacted
      'name': 'John Doe',
    },
  );

  stopwatch.stop();
  Log.http.logResponse(
    method: 'POST',
    url: 'https://api.example.com/v1/users',
    statusCode: 201,
    body: {'id': '123', 'token': 'abc...'},  // Token will be redacted
    duration: stopwatch.elapsed,
  );

  // --- Auth flow logging ---
  Log.auth.logLoginAttempt(method: 'email');
  // On success - note we DON'T pass the token
  Log.auth.logLoginSuccess(method: 'email', userId: 'user-uuid-123');
  // On failure - note we log the reason, NOT the bad password
  Log.auth.logLoginFailure(method: 'email', reason: 'invalid_credentials');
  Log.auth.logTokenRefresh(success: true);
  Log.auth.logMfaChallenge(type: 'totp', success: true);

  // --- Database logging ---
  Log.database.logQuery(
    operation: 'SELECT',
    table: 'users',
    parameters: {'limit': 20, 'offset': 0},
    resultCount: 15,
    duration: const Duration(milliseconds: 23),
  );

  // --- User interaction logging ---
  Log.interaction.logScreenView(screenName: 'ProfileScreen');
  Log.interaction.logButtonTap(
      buttonName: 'save_profile', screenName: 'ProfileScreen');
  Log.interaction.logFormSubmission(
    formName: 'profile_edit',
    success: false,
    errorFields: ['phone_number'], // Field names only, not values
  );

  // --- App health ---
  Log.health.logAppStart(
    startupDuration: const Duration(milliseconds: 1200),
    appVersion: '2.1.0',
    buildNumber: '142',
  );

  // --- General logging ---
  Log.i('payment', 'Payment initiated', metadata: {
    'amount': 29.99,
    'currency': 'USD',
    'paymentMethod': 'card', // No card details
  });

  // --- Error with stack trace ---
  try {
    throw Exception('Something went wrong');
  } catch (e, st) {
    Log.e('payment', 'Payment processing failed',
        error: e, stackTrace: st, metadata: {'orderId': 'order-456'});
  }

  // Ensure logs are flushed before app exit
  await Log.flush();
}

// --- Demonstration of Redaction ---

void demonstrateRedaction() {
  debugPrint('=== Redaction Demonstration ===');

  // Sensitive map redaction
  final sensitiveData = {
    'username': 'john_doe',
    'password': 'super_secret_123',
    'access_token': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.payload.sig',
    'refresh_token': 'rt_abc123def456',
    'email': 'john@example.com',
    'profile': {
      'name': 'John Doe',
      'api_key': 'ak_live_123456789',
      'phone_number': '+1-555-123-4567',
    },
    'credit_card': {
      'card_number': '4111-1111-1111-1111',
      'cvv': '123',
      'expiry': '12/25',
    },
  };

  final redacted = SensitiveDataRedactor.redactMap(sensitiveData);
  debugPrint('Redacted data: ${const JsonEncoder.withIndent('  ').convert(redacted)}');

  // Header redaction
  final headers = {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIs...',
    'X-Api-Key': 'live_key_abc123',
    'Cookie': 'session=abc123; user=john',
  };

  final redactedHeaders = SensitiveDataRedactor.redactHeaders(headers);
  debugPrint('Redacted headers: $redactedHeaders');

  debugPrint('=== End Redaction Demo ===');
}